changeSet.sql:
SET SESSION group_concat_max_len = @@max_allowed_packet;
-- Migration candidates: either an old build script or old Windfile actions. CREATE TEMPORARY TABLE tmp_legacy_build_plan_candidates AS SELECT id, build_script, IF( JSON_VALID(build_plan_configuration), IF( JSON_TYPE(JSON_EXTRACT(build_plan_configuration, '$.metadata.docker.image')) = 'STRING', TRIM(JSON_UNQUOTE(JSON_EXTRACT(build_plan_configuration, '$.metadata.docker.image'))), NULL ), NULL ) AS docker_image, IF( JSON_VALID(build_plan_configuration), IF( JSON_TYPE(JSON_EXTRACT(build_plan_configuration, '$.actions')) = 'ARRAY', JSON_EXTRACT(build_plan_configuration, '$.actions'), JSON_ARRAY() ), JSON_ARRAY() ) AS actions FROM programming_exercise_build_config WHERE build_script IS NOT NULL OR IF( JSON_VALID(build_plan_configuration), JSON_TYPE(JSON_EXTRACT(build_plan_configuration, '$.actions')) = 'ARRAY', FALSE );
-- One row per old Windfile script action for candidates where build_script is missing. CREATE TEMPORARY TABLE tmp_legacy_build_plan_action_script_segments AS SELECT action_rows.id, action_rows.action_ordinal, CONCAT( IF(action_rows.workdir IS NOT NULL AND action_rows.workdir <> '', CONCAT('cd /var/tmp/testing-dir/', action_rows.workdir, '
'), ''), action_rows.script, '
', IF(action_rows.workdir IS NOT NULL AND action_rows.workdir <> '', 'cd /var/tmp/testing-dir
', '') ) AS script_segment FROM ( SELECT candidates.id, actions.action_ordinal, JSON_UNQUOTE(JSON_EXTRACT(actions.action, '$.script')) AS script, IF( JSON_TYPE(JSON_EXTRACT(actions.action, '$.workdir')) = 'STRING', TRIM(JSON_UNQUOTE(JSON_EXTRACT(actions.action, '$.workdir'))), NULL ) AS workdir FROM tmp_legacy_build_plan_candidates candidates JOIN JSON_TABLE(candidates.actions, '$[*]' COLUMNS ( action_ordinal FOR ORDINALITY, action JSON PATH '$' NULL ON EMPTY NULL ON ERROR )) actions WHERE candidates.build_script IS NULL AND JSON_TYPE(JSON_EXTRACT(actions.action, '$.script')) = 'STRING' ) action_rows;
-- Recreate the old LocalCI script from old Windfile script actions. CREATE TEMPORARY TABLE tmp_legacy_build_plan_action_scripts AS SELECT candidates.id, CONCAT( '#!/bin/bash
', 'cd /var/tmp/testing-dir
', COALESCE(GROUP_CONCAT(segments.script_segment ORDER BY segments.action_ordinal SEPARATOR ''), '') ) AS legacy_action_script FROM tmp_legacy_build_plan_candidates candidates LEFT JOIN tmp_legacy_build_plan_action_script_segments segments ON segments.id = candidates.id WHERE candidates.build_script IS NULL GROUP BY candidates.id;
-- One row per textual result path. CREATE TEMPORARY TABLE tmp_legacy_build_plan_result_paths AS SELECT candidates.id AS build_config_id, TRIM(JSON_UNQUOTE(JSON_EXTRACT(results.result, '$.path'))) AS path FROM tmp_legacy_build_plan_candidates candidates JOIN JSON_TABLE(candidates.actions, '$[*].results[*]' COLUMNS (result JSON PATH '$' NULL ON EMPTY NULL ON ERROR)) results WHERE JSON_TYPE(JSON_EXTRACT(results.result, '$.path')) = 'STRING';
-- Aggregate extracted paths back into the JSON array expected by build phases. CREATE TEMPORARY TABLE tmp_legacy_build_plan_result_path_arrays AS SELECT build_config_id, JSON_ARRAYAGG(path) AS paths FROM tmp_legacy_build_plan_result_paths GROUP BY build_config_id;
-- Build the final phases JSON before updating the real table. CREATE TEMPORARY TABLE tmp_legacy_build_plan_converted AS SELECT candidates.id, JSON_OBJECT( 'phases', JSON_ARRAY(JSON_OBJECT( 'name', 'script', 'script', CONCAT('# feel free to remove the code surrounding your script and split your script into multiple phases
', 'cd /var/tmp/testing-dir
', 'local tmp_file=$(mktemp)
', 'cat << '' __LEGACY_INNER_SCRIPT_END__'' > "${tmp_file}" # two leading spaces are intentional as the final script will be indented be for a phase
', COALESCE(candidates.build_script, action_scripts.legacy_action_script, ''), '
__LEGACY_INNER_SCRIPT_END__
', 'chmod +x "${tmp_file}"
', '"${tmp_file}" "$@"
'), 'condition', 'ALWAYS', 'forceRun', FALSE, 'resultPaths', COALESCE(path_arrays.paths, JSON_ARRAY()) )), 'dockerImage', candidates.docker_image ) AS build_plan_configuration FROM tmp_legacy_build_plan_candidates candidates LEFT JOIN tmp_legacy_build_plan_action_scripts action_scripts ON action_scripts.id = candidates.id LEFT JOIN tmp_legacy_build_plan_result_path_arrays path_arrays ON path_arrays.build_config_id = candidates.id;
UPDATE programming_exercise_build_config pebc JOIN tmp_legacy_build_plan_converted converted ON converted.id = pebc.id SET pebc.build_plan_configuration = converted.build_plan_configuration WHERE pebc.id = converted.id;
DROP TEMPORARY TABLE tmp_legacy_build_plan_converted; DROP TEMPORARY TABLE tmp_legacy_build_plan_result_path_arrays; DROP TEMPORARY TABLE tmp_legacy_build_plan_result_paths; DROP TEMPORARY TABLE tmp_legacy_build_plan_action_scripts; DROP TEMPORARY TABLE tmp_legacy_build_plan_action_script_segments; DROP TEMPORARY TABLE tmp_legacy_build_plan_candidates;

CREATE OR REPLACE FUNCTION pg_temp.try_parse_jsonb(input text) RETURNS jsonb LANGUAGE plpgsql AS $$ BEGIN RETURN input::jsonb; EXCEPTION WHEN others THEN RETURN NULL; END; $$;
-- Migration candidates: either an old build script or old Windfile actions. CREATE TEMPORARY TABLE tmp_legacy_build_plan_candidates ON COMMIT DROP AS SELECT pebc.id, pebc.build_script, CASE WHEN jsonb_typeof(legacy_json.config #> '{metadata,docker,image}') = 'string' THEN trim(legacy_json.config #>> '{metadata,docker,image}') END AS docker_image, CASE WHEN jsonb_typeof(legacy_json.config -> 'actions') = 'array' THEN legacy_json.config -> 'actions' ELSE '[]'::jsonb END AS actions FROM programming_exercise_build_config pebc LEFT JOIN LATERAL (SELECT pg_temp.try_parse_jsonb(pebc.build_plan_configuration) AS config) legacy_json ON true WHERE pebc.build_script IS NOT NULL OR jsonb_typeof(legacy_json.config -> 'actions') = 'array';
-- One row per old Windfile script action for candidates where build_script is missing. CREATE TEMPORARY TABLE tmp_legacy_build_plan_action_script_segments ON COMMIT DROP AS SELECT action_rows.id, action_rows.action_ordinal, concat( CASE WHEN action_rows.workdir IS NOT NULL AND action_rows.workdir <> '' THEN concat('cd /var/tmp/testing-dir/', action_rows.workdir, E'
') ELSE '' END, action_rows.script, E'
', CASE WHEN action_rows.workdir IS NOT NULL AND action_rows.workdir <> '' THEN concat('cd /var/tmp/testing-dir', E'
') ELSE '' END ) AS script_segment FROM ( SELECT candidates.id, actions.action_ordinal, actions.action ->> 'script' AS script, CASE WHEN jsonb_typeof(actions.action -> 'workdir') = 'string' THEN trim(actions.action ->> 'workdir') END AS workdir FROM tmp_legacy_build_plan_candidates candidates JOIN LATERAL jsonb_array_elements(candidates.actions) WITH ORDINALITY AS actions(action, action_ordinal) ON true WHERE candidates.build_script IS NULL AND jsonb_typeof(actions.action -> 'script') = 'string' ) action_rows;
-- Recreate the old LocalCI script from old Windfile script actions. CREATE TEMPORARY TABLE tmp_legacy_build_plan_action_scripts ON COMMIT DROP AS SELECT candidates.id, concat( '#!/bin/bash', E'
', 'cd /var/tmp/testing-dir', E'
', COALESCE(string_agg(segments.script_segment, '' ORDER BY segments.action_ordinal), '') ) AS legacy_action_script FROM tmp_legacy_build_plan_candidates candidates LEFT JOIN tmp_legacy_build_plan_action_script_segments segments ON segments.id = candidates.id WHERE candidates.build_script IS NULL GROUP BY candidates.id;
-- One row per textual result path. CREATE TEMPORARY TABLE tmp_legacy_build_plan_result_paths ON COMMIT DROP AS SELECT candidates.id AS build_config_id, trim(results.result ->> 'path') AS path FROM tmp_legacy_build_plan_candidates candidates JOIN LATERAL jsonb_path_query(candidates.actions, '$[*].results[*]') results(result) ON true WHERE jsonb_typeof(results.result -> 'path') = 'string';
-- Aggregate extracted paths back into the JSON array expected by build phases. CREATE TEMPORARY TABLE tmp_legacy_build_plan_result_path_arrays ON COMMIT DROP AS SELECT build_config_id, jsonb_agg(to_jsonb(path)) AS paths FROM tmp_legacy_build_plan_result_paths GROUP BY build_config_id;
-- Build the final phases JSON before updating the real table. CREATE TEMPORARY TABLE tmp_legacy_build_plan_converted ON COMMIT DROP AS SELECT candidates.id, jsonb_build_object( 'phases', jsonb_build_array(jsonb_build_object( 'name', 'script', 'script', concat( '# feel free to remove the code surrounding your script and split your script into multiple phases', E'
', 'cd /var/tmp/testing-dir', E'
', 'local tmp_file=$(mktemp)', E'
', 'cat << '' __LEGACY_INNER_SCRIPT_END__'' > "${tmp_file}" # two leading spaces are intentional as the final script will be indented be for a phase', E'
', COALESCE(candidates.build_script, action_scripts.legacy_action_script, ''), E'
', '__LEGACY_INNER_SCRIPT_END__', E'
', 'chmod +x "${tmp_file}"', E'
', '"${tmp_file}" "$@"', E'
' ), 'condition', 'ALWAYS', 'forceRun', false, 'resultPaths', COALESCE(path_arrays.paths, '[]'::jsonb) )), 'dockerImage', candidates.docker_image )::text AS build_plan_configuration FROM tmp_legacy_build_plan_candidates candidates LEFT JOIN tmp_legacy_build_plan_action_scripts action_scripts ON action_scripts.id = candidates.id LEFT JOIN tmp_legacy_build_plan_result_path_arrays path_arrays ON path_arrays.build_config_id = candidates.id;
UPDATE programming_exercise_build_config pebc SET build_plan_configuration = converted.build_plan_configuration FROM tmp_legacy_build_plan_converted converted WHERE converted.id = pebc.id;
